head.script:
scwin.v_hhio = "";
scwin.hd_kcomcd = "DBEX";
scwin.hid_checkHouseBl = "";
scwin.vCurDate = "";
scwin.strPreDate = "";
scwin.loginClntNo = "";
scwin.loginClntNm = "";
scwin.userClsCd = "";

scwin.onpageload = async function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = $c.date.addDay(scwin.vCurDate, -2);
    scwin.loginClntNo = $c.ses.getClntNo() || "";
    scwin.loginClntNm = $c.ses.getClntNm();
    scwin.userClsCd = $c.ses.getUserClsCd();

    let params = $c.data.getParameter();
    if (params != null && params["hhio"] != null) {
        scwin.v_hhio = params["hhio"];
    }

    scwin.f_set("ONLOAD");
    rd_hhio.setValue(scwin.v_hhio);
    lc_hhbltype.setSelectedIndex(0);
};

scwin.onUdcCompleted = function() {
    scwin.f_dateLoading();
};

scwin.f_set = function(gubun) {
    switch (gubun) {
        case "ONLOAD":
            $c.gus.cfDisableKey();
            cnd_ed_hhvyg.setValue("");
            cnd_ed_hhetdFrom.setValue(scwin.strPreDate);
            cnd_ed_hhetdTo.setValue(scwin.vCurDate);
            ed_hhblno.setFocus();
            break;
        case "RETRIEVE":
            $c.gus.cfEnableAllBtn();
            break;
        case "DELETE":
            $c.gus.cfDisableBtn();
            break;
    }
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([udc_hhetd, udc_hheta]))) {
        return;
    }

    if (rd_hhio.getValue() == "O") {
        if (!$c.gus.cfIsAfterDate(udc_hhetd.getFromValue(), udc_hhetd.getToValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD From", "ETD To"]);
            udc_hhetd.setFocusFrom();
            return false;
        }
    } else {
        if (!$c.gus.cfIsAfterDate(udc_hheta.getFromValue(), udc_hheta.getToValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETA From", "ETA To"]);
            udc_hheta.setFocusFrom();
            return false;
        }
    }

    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("hhetdFrom", udc_hhetd.getFromValue());
    ds_retrieve.set("hhetdTo", udc_hhetd.getToValue());
    ds_retrieve.set("hhetaFrom", udc_hheta.getFromValue());
    ds_retrieve.set("hhetaTo", udc_hheta.getToValue());
    ds_retrieve.set("hhvyg", cnd_ed_hhvyg.getValue());

    if (txt_item.getValue() != "" || txt_item.getValue() != null) {
        ds_retrieve.set("hhmitem2", ds_retrieve.get("hhmitem2").toUpperCase());
    }

    await $c.sbm.execute(sbm_retrieve);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([tb_searchCondition]);
    scwin.f_set("ONLOAD");
    scwin.f_dateLoading();
};

scwin.f_validate = function() {
};

