scwin.f_downExcelSheet = async function() {
    let cntRow = ds_houseblList.getRowCount();

    if (cntRow != 0) {
        let cfrm = await $c.win.confirm("House B/L List를 EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_houseblList, {
                fileName: "House BL List.xlsx",
                sheetName: "House BL List"
            });
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

scwin.f_dateLoading = function() {
    if (rd_hhio.getValue() == "O") {
        udc_hhetd.setInitDate(scwin.strPreDate, scwin.vCurDate);
        udc_hheta.setInitDate("", "");
    } else {
        udc_hhetd.setInitDate("", "");
        udc_hheta.setInitDate(scwin.strPreDate, scwin.vCurDate);
    }
};

scwin.rd_hhio_onviewchange = function(e) {
    scwin.f_dateLoading();
};

