scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_houseblList.getRowCount() > 0) {
        let cnt = 0;
        let documentNo = "";

        for (let i = 0; i < ds_houseblList.getRowCount(); i++) {
            if (documentNo != ds_houseblList.getCellData(i, "hhblno")) {
                cnt++;
            }
            documentNo = ds_houseblList.getCellData(i, "hhblno");
        }

        spa_totalRow.setValue(ds_houseblList.getRowCount());
        spa_totalRow2.setValue(cnt);

        scwin.f_set("RETRIEVE");
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.gr_houseblList_oncelldblclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        if (columnId == "trYn") {
            $c.win.openMenu("컨테이너 경로 관리", "/ui/il/custsv/tr/cs_108_01_02b.xml", "cs_108_01_02b.xml", {
                hblNo: ds_houseblList.getCellData(rowIndex, "hhblno")
            });
        } else {
            if (ds_houseblList.getCellData(rowIndex, "hhio") == "O") {
                if (ds_houseblList.getCellData(rowIndex, "autono") == "DIRECT" && ds_houseblList.getCellData(rowIndex, "hhbltype") != "B") {
                    $c.win.openMenu("Export House B/L", "/ui/il/seaout/sobl/se_107_01_01b.xml", "se_107_01_01b.xml", {
                        linkcheck: "2",
                        kcomcd: scwin.hd_kcomcd,
                        blno: ds_houseblList.getCellData(rowIndex, "hhblno"),
                        mhno: ds_houseblList.getCellData(rowIndex, "mhno")
                    });
                } else if (ds_houseblList.getCellData(rowIndex, "autono") == "DIRECT" && ds_houseblList.getCellData(rowIndex, "hhbltype") == "B") {
                    $c.win.openMenu("Export Bulk B/L", "/ui/il/seaout/sobl/se_108_01_01b.xml", "se_108_01_01b.xml", {
                        linkcheck: "2",
                        kcomcd: scwin.hd_kcomcd,
                        mhno: ds_houseblList.getCellData(rowIndex, "mhno")
                    });
                } else {
                    $c.win.openMenu("Export House B/L (New)", "/ui/il/seaout/sobl/se_105_01_05b.xml", "se_105_01_05b.xml", {
                        linkcheck: "2",
                        kcomcd: scwin.hd_kcomcd,
                        blno: ds_houseblList.getCellData(rowIndex, "hhblno"),
                        mhno: ds_houseblList.getCellData(rowIndex, "mhno")
                    });
                }
            } else {
                if (ds_houseblList.getCellData(rowIndex, "autono") == "DIRECT" && ds_houseblList.getCellData(rowIndex, "hhbltype") == "B") {
                    $c.win.openMenu("Import Bulk B/L", "/ui/il/seainb/sibl/se_203_01_01b.xml", "se_203_01_01b.xml", {
                        linkcheck: "2",
                        kcomcd: scwin.hd_kcomcd,
                        mhno: ds_houseblList.getCellData(rowIndex, "mhno")
                    });
                } else {
                    $c.win.openMenu("Import House B/L (New)", "/ui/il/seainb/sibl/se_201_01_03b.xml", "se_201_01_03b.xml", {
                        linkcheck: "2",
                        kcomcd: scwin.hd_kcomcd,
                        blno: ds_houseblList.getCellData(rowIndex, "hhblno"),
                        mhno: ds_houseblList.getCellData(rowIndex, "mhno")
                    });
                }
            }
        }
    }
};
